import { IMessageComposer } from '@nitrots/nitro-renderer';

export class DeleteGangRoleComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(rankId: number) {
        this._data = [rankId];
    }

    public getMessageArray(): any[] {
        console.log('Sending DeleteGangRoleComposer with data:', this._data);
        return this._data;
    }

    public dispose(): void {}
}
